+/* ─── Deterministic PRNG ─────────────────────────────────────────── */
+
+function mulberry32(seed: number) {
+  const s = (seed + 0x6d2b79f5) | 0;
+  let t = Math.imul(s ^ (s >>> 15), 1 | s);
+  t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
+  return {
+    seed: s,
+    value: ((t ^ (t >>> 14)) >>> 0) / 4294967296,
+  };
+}
+
+function nextRandom(seed: number) {
+  return mulberry32(seed);
